let _audit = AiAgentAudit_CL
  | where TimeGenerated {TimeRange}
  | extend
      agent_type_x=tostring(column_ifexists('agent_type_s', column_ifexists('agent_type', ''))),
      action_type_x=tostring(column_ifexists('action_type_s', column_ifexists('action_type', ''))),
      policy_decision_x=tostring(column_ifexists('policy_decision_s', column_ifexists('policy_decision', ''))),
      outcome_x=tostring(column_ifexists('outcome_s', column_ifexists('outcome', ''))),
      run_id_x=tostring(column_ifexists('run_id_s', column_ifexists('run_id', ''))),
      error_code_x=tostring(column_ifexists('error_code_s', column_ifexists('error_code', '')))
  | where agent_type_x in~ ({AgentType}) or '*' in~ ({AgentType})
  | where action_type_x in~ ({ActionType}) or '*' in~ ({ActionType})
  | where '{RunId}' == '' or run_id_x has '{RunId}';
let _events = toscalar(_audit | count);
let _runs   = toscalar(_audit | summarize dcount(run_id_x));
let _agents = toscalar(_audit | summarize dcount(agent_type_x));
let _starts = toscalar(_audit | where action_type_x == 'run_start' | count);
let _completes = toscalar(_audit | where action_type_x == 'run_complete' | count);
let _aborts = toscalar(_audit | where action_type_x == 'run_abort' | count);
let _errors = toscalar(_audit | where isnotempty(error_code_x) | count);
union
  (print Name='Events', Value=todouble(_events), Order=1),
  (print Name='Active runs', Value=todouble(_runs), Order=2),
  (print Name='Agents involved', Value=todouble(_agents), Order=3),
  (print Name='Avg events / run', Value=iif(_runs>0, round(todouble(_events)/todouble(_runs),1), 0.0), Order=4),
  (print Name='Runs started', Value=todouble(_starts), Order=5),
  (print Name='Runs completed', Value=todouble(_completes), Order=6),
  (print Name='Runs aborted', Value=todouble(_aborts), Order=7),
  (print Name='Error rate %', Value=iif(_events>0, round(100.0*todouble(_errors)/todouble(_events),1), 0.0), Order=8)
| order by Order asc
| project Name, Value

let _audit = AiAgentAudit_CL
  | where TimeGenerated {TimeRange}
  | extend
      agent_type_x=tostring(column_ifexists('agent_type_s', column_ifexists('agent_type', ''))),
      action_type_x=tostring(column_ifexists('action_type_s', column_ifexists('action_type', ''))),
      policy_decision_x=tostring(column_ifexists('policy_decision_s', column_ifexists('policy_decision', ''))),
      outcome_x=tostring(column_ifexists('outcome_s', column_ifexists('outcome', ''))),
      run_id_x=tostring(column_ifexists('run_id_s', column_ifexists('run_id', '')))
  | where agent_type_x in~ ({AgentType}) or '*' in~ ({AgentType})
  | where action_type_x in~ ({ActionType}) or '*' in~ ({ActionType})
  | where '{RunId}' == '' or run_id_x has '{RunId}';
let _events = toscalar(_audit | count);
let _allow  = toscalar(_audit | where policy_decision_x == 'allow' | count);
let _deny   = toscalar(_audit | where policy_decision_x == 'deny' | count);
let _block  = toscalar(_audit | where outcome_x == 'blocked' | count);
let _req    = toscalar(_audit | where policy_decision_x == 'requires_approval' or action_type_x == 'approval_request' | count);
let _resp   = toscalar(_audit | where action_type_x == 'approval_response' | count);
let _grant  = toscalar(_audit | where action_type_x == 'approval_response' and outcome_x == 'granted' | count);
let _kill   = toscalar(_audit | where action_type_x in ('kill_switch_check','admin_kill_switch_toggle') | count);
union
  (print Name='Allowed', Value=todouble(_allow), Order=1),
  (print Name='Denied', Value=todouble(_deny), Order=2),
  (print Name='Blocked', Value=todouble(_block), Order=3),
  (print Name='Approvals requested', Value=todouble(_req), Order=4),
  (print Name='Approvals responded', Value=todouble(_resp), Order=5),
  (print Name='Approvals granted', Value=todouble(_grant), Order=6),
  (print Name='Block rate %', Value=iif(_events>0, round(100.0*todouble(_deny+_block)/todouble(_events),1), 0.0), Order=7),
  (print Name='Kill-switch events', Value=todouble(_kill), Order=8)
| order by Order asc
| project Name, Value

let _audit = AiAgentAudit_CL
  | where TimeGenerated {TimeRange}
  | extend
      agent_type_x=tostring(column_ifexists('agent_type_s', column_ifexists('agent_type', ''))),
      action_type_x=tostring(column_ifexists('action_type_s', column_ifexists('action_type', ''))),
      policy_decision_x=tostring(column_ifexists('policy_decision_s', column_ifexists('policy_decision', ''))),
      outcome_x=tostring(column_ifexists('outcome_s', column_ifexists('outcome', ''))),
      run_id_x=tostring(column_ifexists('run_id_s', column_ifexists('run_id', ''))),
      dlp_patterns_x=tostring(column_ifexists('dlp_patterns_s', column_ifexists('dlp_patterns', ''))),
      content_safety_x=tostring(column_ifexists('content_safety_category_s', column_ifexists('content_safety_category', ''))),
      injection_score_x=todouble(column_ifexists('injectionScore', column_ifexists('injection_score_d', column_ifexists('injection_score', real(null)))))
  | where agent_type_x in~ ({AgentType}) or '*' in~ ({AgentType})
  | where action_type_x in~ ({ActionType}) or '*' in~ ({ActionType})
  | where '{RunId}' == '' or run_id_x has '{RunId}';
let _injBlock = toscalar(_audit | where action_type_x == 'prompt_shield_scan' and (policy_decision_x == 'deny' or outcome_x == 'blocked' or injection_score_x >= 0.7) | count);
let _dlp      = toscalar(_audit | where action_type_x == 'dlp_scan' and (policy_decision_x == 'deny' or outcome_x == 'blocked' or isnotempty(dlp_patterns_x)) | count);
let _cs       = toscalar(_audit | where action_type_x in ('content_safety_check','content_safety_scan','retrieved_content_scan') and (policy_decision_x == 'deny' or outcome_x == 'blocked' or isnotempty(content_safety_x)) | count);
let _exc      = toscalar(_audit | where action_type_x == 'excessive_agency_block' | count);
let _sig      = toscalar(_audit | where action_type_x == 'signature_verification_failure' | count);
let _xt       = toscalar(_audit | where action_type_x == 'cross_tenant_access_attempt' | count);
let _deleg    = toscalar(_audit | where action_type_x in ('delegation_check','agent_delegation') and (policy_decision_x == 'deny' or outcome_x == 'blocked') | count);
let _ground   = toscalar(_audit | where action_type_x == 'grounding_check' and outcome_x == 'blocked' | count);
let _runsHit  = toscalar(_audit | where action_type_x in ('prompt_shield_scan','dlp_scan','content_safety_check','content_safety_scan','retrieved_content_scan','excessive_agency_block','signature_verification_failure','cross_tenant_access_attempt','delegation_check','agent_delegation','grounding_check') and (policy_decision_x == 'deny' or outcome_x == 'blocked' or isnotempty(dlp_patterns_x) or isnotempty(content_safety_x) or injection_score_x >= 0.7) | summarize dcount(run_id_x));
union
  (print Name='Prompt-injection blocks', Value=todouble(_injBlock), Order=1),
  (print Name='DLP interceptions', Value=todouble(_dlp), Order=2),
  (print Name='Content safety blocks', Value=todouble(_cs), Order=3),
  (print Name='Excessive agency (LLM08)', Value=todouble(_exc), Order=4),
  (print Name='Signature failures', Value=todouble(_sig), Order=5),
  (print Name='Cross-tenant attempts', Value=todouble(_xt), Order=6),
  (print Name='Untrusted delegation', Value=todouble(_deleg), Order=7),
  (print Name='Grounding failures', Value=todouble(_ground), Order=8),
  (print Name='Runs with detections', Value=todouble(_runsHit), Order=9)
| order by Order asc
| project Name, Value

let _audit = AiAgentAudit_CL
  | where TimeGenerated {TimeRange}
  | extend
      agent_type_x=tostring(column_ifexists('agent_type_s', column_ifexists('agent_type', ''))),
      action_type_x=tostring(column_ifexists('action_type_s', column_ifexists('action_type', ''))),
      outcome_x=tostring(column_ifexists('outcome_s', column_ifexists('outcome', ''))),
      run_id_x=tostring(column_ifexists('run_id_s', column_ifexists('run_id', ''))),
      token_count_x=toint(column_ifexists('token_count_d', column_ifexists('token_count', int(0)))),
      cost_x=todouble(column_ifexists('estimatedCostUsd', column_ifexists('estimated_cost_usd_d', column_ifexists('estimated_cost_usd', real(null))))),
      anomaly_score_x=todouble(column_ifexists('anomalyScore', column_ifexists('anomaly_score_d', column_ifexists('anomaly_score', real(null)))))
  | where agent_type_x in~ ({AgentType}) or '*' in~ ({AgentType})
  | where action_type_x in~ ({ActionType}) or '*' in~ ({ActionType})
  | where '{RunId}' == '' or run_id_x has '{RunId}';
let _anom    = toscalar(_audit | where action_type_x == 'anomaly_ml_score' and isnotnull(anomaly_score_x) and anomaly_score_x >= 0.7 | count);
let _cost_br = toscalar(_audit | where action_type_x == 'cost_threshold_breach' | count);
let _costSum = toscalar(_audit | summarize sum(cost_x));
let _tokens  = toscalar(_audit | summarize sum(token_count_x));
let _loop    = toscalar(_audit | where action_type_x in ('loop_detected','loop_halt') | count);
let _mcp     = toscalar(_audit | where action_type_x in ('mcp_tool_call','mcp_tool_discovery') | count);
let _rl      = toscalar(_audit | where action_type_x == 'rate_limit_exceeded' | count);
let _dsar    = toscalar(_audit | where action_type_x in ('admin_dsar_export','dsar_purge','dsar_request') | count);
let _gov     = toscalar(_audit | where action_type_x == 'governance_attestation' | count);
union
  (print Name='Anomalies (>=0.7)', Value=todouble(_anom), Order=1),
  (print Name='Cost-threshold breaches', Value=todouble(_cost_br), Order=2),
  (print Name='Est. spend (USD)', Value=round(coalesce(_costSum, 0.0),2), Order=3),
  (print Name='Tokens consumed', Value=todouble(coalesce(_tokens, 0)), Order=4),
  (print Name='Loop halts', Value=todouble(_loop), Order=5),
  (print Name='MCP tool calls', Value=todouble(_mcp), Order=6),
  (print Name='Rate-limit blocks', Value=todouble(_rl), Order=7),
  (print Name='DSAR operations', Value=todouble(_dsar), Order=8),
  (print Name='Governance attestations', Value=todouble(_gov), Order=9)
| order by Order asc
| project Name, Value
